import axios from 'axios';

const API_BASE_URL = 'http://localhost:8080/students';

const studentApi = axios.create({
  baseURL: API_BASE_URL,
});

export const getStudents = () => studentApi.get('/');

export const addStudent = (student) => studentApi.post('/', student);

export const updateStudent = (id, student) => studentApi.put(`/${id}`, student);

export const deleteStudent = (id) => studentApi.delete(`/${id}`);
